                                                    const size = device ? getDiModuleSize(device) : { width: DI_SLOT_SIZE, height: DI_SLOT_SIZE };
                                                    const slotPos = getDiSlotPosition(slotIndex);
                                                    const slotX = slotPos.x;
                                                    const slotY = slotPos.y;
